import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"Fleet Overview — A2A Agent Fleet","description":"","frontmatter":{},"headers":[],"relativePath":"fleet/overview.md","filePath":"fleet/overview.md"}'),s={name:"fleet/overview.md"};function o(l,e,i,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="fleet-overview-—-a2a-agent-fleet" tabindex="-1">Fleet Overview — A2A Agent Fleet <a class="header-anchor" href="#fleet-overview-—-a2a-agent-fleet" aria-label="Permalink to &quot;Fleet Overview — A2A Agent Fleet&quot;">​</a></h1><p><strong>Status:</strong> Active <strong>Owner:</strong> SIN-Zeus (Fleet Commander)</p><hr><h2 id="what-is-the-fleet" tabindex="-1">What Is The Fleet? <a class="header-anchor" href="#what-is-the-fleet" aria-label="Permalink to &quot;What Is The Fleet?&quot;">​</a></h2><p>The OpenSIN-AI Fleet is a network of autonomous A2A (Agent-to-Agent) agents that collaborate across repositories, platforms, and services. Each agent is a self-contained process with its own tools, skills, and Telegram bot — coordinated by Team Managers and the global orchestrator SIN-Zeus.</p><hr><h2 id="fleet-architecture" tabindex="-1">Fleet Architecture <a class="header-anchor" href="#fleet-architecture" aria-label="Permalink to &quot;Fleet Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────┐</span></span>
<span class="line"><span>│               SIN-Zeus                        │</span></span>
<span class="line"><span>│          (Fleet Commander)                    │</span></span>
<span class="line"><span>├──────────────────┬───────────────────────────┤</span></span>
<span class="line"><span>│  Team Managers   │   Global Agents           │</span></span>
<span class="line"><span>│  ─────────────   │   ─────────────           │</span></span>
<span class="line"><span>│  Team Coding     │   SIN-Hermes (Dispatcher) │</span></span>
<span class="line"><span>│  Team Worker     │   SIN-Herakles (Backend)  │</span></span>
<span class="line"><span>│  Team Infra      │   SIN-Solver (Web App)    │</span></span>
<span class="line"><span>│  Team Google     │   SIN-Research            │</span></span>
<span class="line"><span>│  Team Media      │   SIN-Patents             │</span></span>
<span class="line"><span>│  Team Microsoft  │   ...                     │</span></span>
<span class="line"><span>└──────────────────┴───────────────────────────┘</span></span></code></pre></div><hr><h2 id="agent-categories" tabindex="-1">Agent Categories <a class="header-anchor" href="#agent-categories" aria-label="Permalink to &quot;Agent Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Count</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Team Managers</strong></td><td>5+</td><td>Team Coding, Team Worker, Team Infra, Team Google Apps, Team Microsoft</td></tr><tr><td><strong>Coding Agents</strong></td><td>10+</td><td>Simone-MCP, Frontend, Backend, DevOps, DataScience, GitLab-LogsCenter</td></tr><tr><td><strong>Platform Agents</strong></td><td>30+</td><td>Prolific, HeyPiggy, Mindrift, Instagram, TikTok, YouTube, LinkedIn</td></tr><tr><td><strong>Messaging Agents</strong></td><td>15+</td><td>WhatsApp, Telegram, Discord, Signal, Slack, Teams, WeChat, LINE</td></tr><tr><td><strong>Apple Agents</strong></td><td>10+</td><td>Mail, Notes, Calendar, Safari, Shortcuts, Photos, FaceTime</td></tr><tr><td><strong>Infrastructure</strong></td><td>5+</td><td>Storage, Stripe, Chrome Extension, Computer Use, Memory</td></tr></tbody></table><hr><h2 id="fleet-communication" tabindex="-1">Fleet Communication <a class="header-anchor" href="#fleet-communication" aria-label="Permalink to &quot;Fleet Communication&quot;">​</a></h2><ul><li><strong>A2A Protocol</strong>: Agent-to-Agent JSON-RPC over HTTP</li><li><strong>Telegram</strong>: Fleet-wide alerts, operator chat, incident escalation</li><li><strong>Neural-Bus</strong>: NATS JetStream event mesh (WIP — see <a href="/architecture/global-brain-neural-bus.html">Neural-Bus docs</a>)</li><li><strong>GitHub</strong>: Issues, PRs, and the Fleet Operations project board</li></ul><hr><h2 id="agent-lifecycle" tabindex="-1">Agent Lifecycle <a class="header-anchor" href="#agent-lifecycle" aria-label="Permalink to &quot;Agent Lifecycle&quot;">​</a></h2><ol><li><strong>Create</strong>: Generated from <code>Template-SIN-Agent</code> via <code>/create-a2a-sin-agent</code> skill</li><li><strong>Deploy</strong>: Pushed to GitHub, Cloudflare Workers, or HF Space</li><li><strong>Register</strong>: Added to fleet registry and team configuration</li><li><strong>Operate</strong>: Autonomous task execution, self-healing via GitHub Issues</li><li><strong>Monitor</strong>: GitLab LogCenter collects logs, errors trigger auto-issues</li></ol><hr><h2 id="key-repositories" tabindex="-1">Key Repositories <a class="header-anchor" href="#key-repositories" aria-label="Permalink to &quot;Key Repositories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Repo</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/OpenSIN-AI/Template-SIN-Agent" target="_blank" rel="noreferrer">Template-SIN-Agent</a></td><td>Blueprint for all agents</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/Template-SIN-Team" target="_blank" rel="noreferrer">Template-SIN-Team</a></td><td>Blueprint for team managers</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-documentation" target="_blank" rel="noreferrer">OpenSIN-documentation</a></td><td>Fleet docs (this repo)</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-Code" target="_blank" rel="noreferrer">OpenSIN-Code</a></td><td>CLI core, plugins, engine</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-Neural-Bus" target="_blank" rel="noreferrer">OpenSIN-Neural-Bus</a></td><td>Event-sourcing mesh</td></tr><tr><td><a href="https://github.com/orgs/OpenSIN-AI/projects/21" target="_blank" rel="noreferrer">Fleet Operations Project</a></td><td>Tracking board</td></tr></tbody></table><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/governance/overview.html">Governance Overview</a></li><li><a href="/architecture/a2a.html">A2A Architecture</a></li><li><a href="/guide/team-orchestration.html">Team Orchestration</a></li><li><a href="/guide/agent-configuration.html">Agent Configuration</a></li></ul>`,23)])])}const u=t(s,[["render",o]]);export{g as __pageData,u as default};
